import{_ as s,c as a,o as e,a as n}from"./app.28628e18.js";var o="/vue-forms/assets/accessible-errors1.008f0860.jpg",l="/vue-forms/assets/accessible-errors2.48138e64.jpg",p="/vue-forms/assets/accessible-errors3.1525aa13.jpg";const A=JSON.parse('{"title":"Errores Accesibles","description":"","frontmatter":{},"headers":[{"level":2,"title":"Estado de entrada expl\xEDcito","slug":"estado-de-entrada-explicito"},{"level":2,"title":"No deshabilites el bot\xF3n de enviar","slug":"no-deshabilites-el-boton-de-enviar"},{"level":2,"title":"Terminando","slug":"terminando"}],"relativePath":"tuto/accessible-errors.md"}'),r={name:"tuto/accessible-errors.md"},t=n(`<h1 id="errores-accesibles" tabindex="-1">Errores Accesibles <a class="header-anchor" href="#errores-accesibles" aria-hidden="true">#</a></h1><blockquote><p>\xBFAlguna vez llen\xF3 un formulario solo para presionar el bot\xF3n de enviar y nada parec\xEDa funcionar? Claramente no se estaba enviando, y no hab\xEDa ning\xFAn error visible en ninguna parte, sin embargo, algo estaba claramente mal. Esta situaci\xF3n no es ajena a la mayor\xEDa de los usuarios de Internet, pero imagine la exasperaci\xF3n cuando necesita herramientas accesibles y el formulario no le dice f\xE1cilmente cu\xE1l es el problema con sus entradas.</p></blockquote><p>Primero vayamos a nuestro componente <code>AppInput.vue</code> y agreguemos una nueva propiedad, <code>error</code>, que nos permitir\xE1 establecer una cadena con un mensaje de error en caso de que el componente se encuentre en un estado de error.</p><p>\u{1F4C3}<code>AppInput.vue</code></p><div class="language-ts"><span class="copy"></span><div class="highlight-lines"><br><br><br><div class="highlighted">\xA0</div><br><br><br><div class="highlighted">\xA0</div><br><br></div><pre><code><span class="line"><span style="color:#82AAFF;">withDefaults</span><span style="color:#A6ACCD;">(</span><span style="color:#82AAFF;">defineProps</span><span style="color:#89DDFF;">&lt;{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">label</span><span style="color:#89DDFF;">?:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">string</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">modelValue</span><span style="color:#89DDFF;">?:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">string</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">number</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">error</span><span style="color:#89DDFF;">?:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">string</span></span>
<span class="line"><span style="color:#89DDFF;">}&gt;</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">label</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">modelValue</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">error</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;&#39;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><p>Mostraremos este <code>error</code> debajo de nuestro campo <code>input</code> cada vez que haya un <code>error</code> presente, si la propiedad de <code>error</code> se establece en algo que no sea una cadena vac\xEDa.</p><p>\u{1F4C3}<code>AppInput.vue</code></p><div class="language-vue"><span class="copy"></span><div class="highlight-lines"><br><br><br><br><br><br><br><br><br><br><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><br><br></div><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;"> :</span><span style="color:#C792EA;">for</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> label </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-bind</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">$attrs</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">modelValue</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">placeholder</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    @</span><span style="color:#C792EA;">input</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#82AAFF;">$emit</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">update:modelValue</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">, (</span><span style="color:#A6ACCD;">$event</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">target</span><span style="color:#89DDFF;"> </span><span style="color:#89DDFF;font-style:italic;">as</span><span style="color:#89DDFF;"> </span><span style="color:#FFCB6B;">HTMLInputElement</span><span style="color:#89DDFF;">).</span><span style="color:#A6ACCD;">value</span><span style="color:#89DDFF;">)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">field</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">  </span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{{</span><span style="color:#A6ACCD;"> error </span><span style="color:#89DDFF;">}}</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Tambi\xE9n volveremos a <code>TasksForm.vue</code> y agregaremos un mensaje de <code>error</code> a nuestra entrada <strong>&#39;Name&#39;</strong>, para que podamos ver c\xF3mo se comporta en el navegador. Tenga en cuenta que tambi\xE9n agregamos una clase de mensaje <code>error</code> que simplemente lo colorear\xE1 de rojo.</p><p>\u{1F4C3}<code>TasksForm.vue</code></p><div class="language-html"><span class="copy"></span><div class="highlight-lines"><br><br><br><br><div class="highlighted">\xA0</div><br><br></div><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">AppInput</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-model</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">form.name</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">label</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Name</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">error</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">This input has an error!</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">/&gt;</span></span>
<span class="line"></span></code></pre></div><p>Ahora echemos un vistazo al navegador, el <code>error</code> se muestra correctamente debajo del t\xEDtulo una vez que se establece la propiedad <code>error</code>. Tenga en cuenta que si tuviera m\xE1s componentes <code>AppInput</code> dentro del formulario <code>TasksForm</code>, estos otros no mostrar\xE1n ning\xFAn <code>error</code> porque la propiedad <code>error</code> no est\xE1n configuradas en nada para ellos.</p><p><img src="`+o+`" alt="accessible-errors"></p><p>Si abrimos nuestra pesta\xF1a de <strong>Accessibility</strong> en Firefox una vez m\xE1s e inspeccionamos el elemento <code>input</code>, podemos ver que no hay nada que vincule el <code>error</code> con el <code>input</code> del nombre real. Aqu\xED es donde la mayor\xEDa de los formularios se quedan cortos. El hecho de que el mensaje <code>error</code> est\xE9 &quot;cerca&quot; del <code>input</code> no significa que un lector de pantalla pueda identificarlo como parte del <code>error</code>.</p><blockquote><p>Afortunadamente, hay una soluci\xF3n sencilla a este problema: el atributo <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-describedby" target="_blank" rel="noopener noreferrer"><code>aria-describedby</code></a>. Este atributo nos permite establecer directamente en el elemento de entrada qu\xE9 otros elementos lo describen.</p></blockquote><p>El atributo puede tomar una lista de cadenas de <strong>ID</strong> para otros elementos <strong>HTML</strong> en la p\xE1gina, as\xED que primero agregaremos una <strong>ID</strong> \xFAnico a nuestra etiqueta. Por suerte, ya tenemos un n\xFAmero <strong>UUID</strong> asociado a la instancia del componente para hacerlo.</p><p>Volvamos a <code>AppInput</code> y agreguemos el v\xEDnculo <code>id</code> a la etiqueta <code>p</code> de <code>error</code>.</p><p>\u{1F4C3}<code>AppInput.vue</code></p><div class="language-html"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">\`\${uuid}-error\`</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  {{ error }}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Tenga en cuenta que estamos agregando la cadena <code>-error</code> al <code>UUID</code>. Necesitamos que este identificador sea \xFAnico, y el <code>UUID</code> en s\xED mismo ya est\xE1 en uso por el <code>input</code>.</p><p>Ahora que nuestro mensaje de error tiene un <strong>ID</strong> \xFAnico, podemos establecerlo como una <em>&quot;descripci\xF3n&quot;</em> para el elemento <code>input</code> con el atributo <code>aria-describedby</code>.</p><p>\u{1F4C3}<code>AppInput.vue</code></p><div class="language-vue"><span class="copy"></span><div class="highlight-lines"><br><br><br><br><br><br><br><br><br><div class="highlighted">\xA0</div><br><br><br><br><br><br><br><br><br><br></div><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;"> :</span><span style="color:#C792EA;">for</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> label </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-bind</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">$attrs</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">modelValue</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">placeholder</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    @</span><span style="color:#C792EA;">input</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#82AAFF;">$emit</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">update:modelValue</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">, (</span><span style="color:#A6ACCD;">$event</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">target</span><span style="color:#89DDFF;"> </span><span style="color:#89DDFF;font-style:italic;">as</span><span style="color:#89DDFF;"> </span><span style="color:#FFCB6B;">HTMLInputElement</span><span style="color:#89DDFF;">).</span><span style="color:#A6ACCD;">value</span><span style="color:#89DDFF;">)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">field</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">    </span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">aria-describedby</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">error</span><span style="color:#89DDFF;"> ? </span><span style="color:#89DDFF;">\`\${</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">}</span><span style="color:#C3E88D;">-error</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;"> : undefined</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;\`\${</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">}</span><span style="color:#C3E88D;">-error</span><span style="color:#89DDFF;">\`&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{{</span><span style="color:#A6ACCD;"> error </span><span style="color:#89DDFF;">}}</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Tenga en cuenta que estamos agregando una verificaci\xF3n secundaria para ver si se establece un <code>error</code>. Esto nos permite un poco de higiene en la relaci\xF3n entre nuestros elementos: cuando no hay ning\xFAn <code>error</code> presente, no se mostrar\xE1 ning\xFAn mensaje de <code>error</code> y la identificaci\xF3n no apuntar\xE1 a nada.</p><p>Si volvemos a revisar nuestro navegador, podemos ver que cuando el <code>error</code> est\xE1 presente, una nueva descripci\xF3n por entrada est\xE1 presente en el objeto de relaci\xF3n de la entrada.</p><p><img src="`+l+`" alt="accessible-errors"></p><p>Sin embargo, una cosa m\xE1s... Debido a que estamos usando <code>v-if</code> para mostrar esta informaci\xF3n de forma intermitente, queremos asegurarnos de que los lectores de pantalla la anuncien o la lean cada vez que se muestre. Para hacer esto, agregaremos un atributo <code>aria-live=&quot;asertive&quot;</code>. Otra forma ser\xEDa agregar un atributo <code>rol</code> de <code>&quot;alert&quot;</code>, pero descubrimos que <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-live" target="_blank" rel="noopener noreferrer"><code>aria-live</code></a> tiende a funcionar mejor con un variedad de lectores de pantalla.</p><p>\u{1F4C3}<code>AppInput.vue</code></p><div class="language-html"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">\`\${uuid}-error\`</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">aria-live</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">assertive</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  {{ error }}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><h2 id="estado-de-entrada-explicito" tabindex="-1">Estado de entrada expl\xEDcito <a class="header-anchor" href="#estado-de-entrada-explicito" aria-hidden="true">#</a></h2><p>Otra cosa que podemos agregar r\xE1pidamente a nuestra entrada para que sea a\xFAn m\xE1s accesible es el atributo <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-invalid" target="_blank" rel="noopener noreferrer"><code>aria-invalid</code></a>. Un error que se comete en muchos formularios es tratar de confiar en un borde rojo alrededor de una entrada no v\xE1lida. Por razones obvias, esto no es accesible.</p><p>Ya hemos tomado medidas en errores accesibles, pero asegur\xE9monos de notificar tambi\xE9n a los lectores de pantalla sobre el estado no v\xE1lido de una entrada para proporcionar mejores comentarios a nuestros usuarios.</p><p>Vamos a agregar el atributo <code>aria-invalid</code> a nuestra entrada, y lo activaremos y desactivaremos dependiendo de si la propiedad <code>error</code> est\xE1 establecida. Cuando la entrada es v\xE1lida, <code>undefined</code> har\xE1 que la propiedad no se agregue al elemento de entrada.</p><p>\u{1F4C3}<code>AppInput.vue</code></p><div class="language-html"><span class="copy"></span><div class="highlight-lines"><br><br><br><br><br><br><br><br><div class="highlighted">\xA0</div><br><br></div><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-bind</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">$attrs</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">modelValue</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:placeholder</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">label</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">@input</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">$emit(&#39;update:modelValue&#39;, ($event.target as HTMLInputElement).value)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">field</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">    </span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:aria-describedby</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error ? \`\${uuid}-error\` : undefined</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:aria-invalid</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error ? true : undefined</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Si volvemos al navegador e inspeccionamos la entrada usando la herramienta de <strong>Accessibility</strong> en <strong>Firefox</strong>, podemos ver que el estado <code>&quot;invalid&quot;</code> ahora se ha agregado a los estados activos del <code>input</code>.</p><p><img src="`+p+'" alt="accessible-errors"></p><p>Otros estados dignos de menci\xF3n a los que tambi\xE9n podr\xEDamos agregar atributos son de <code>readonly</code>, <code>disabled</code> y <code>required</code>. Estos tres se pueden establecer directamente con atributos <strong>HTML5</strong> del mismo nombre, o con sus contrapartes aria: <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-readonly" target="_blank" rel="noopener noreferrer"><code>aria-readonly</code></a>, <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-disabled" target="_blank" rel="noopener noreferrer"><code>aria-disabled</code></a> y <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-required" target="_blank" rel="noopener noreferrer"><code>aria-required</code></a>.</p><h2 id="no-deshabilites-el-boton-de-enviar" tabindex="-1">No deshabilites el bot\xF3n de enviar <a class="header-anchor" href="#no-deshabilites-el-boton-de-enviar" aria-hidden="true">#</a></h2><p>Si un formulario no es v\xE1lido, tiene sentido establecer el atributo <code>disabled</code> en <code>true</code> en el bot\xF3n <code>submit</code> para que el usuario no pueda enviar el formulario, \xBFverdad? Incluso podemos dise\xF1ar el bot\xF3n con un color diferente para transmitir que no se podr\xE1 hacer click en \xE9l.</p><p>Sin embargo, hay un gran problema con esto. Los usuarios que conf\xEDan en los lectores de pantalla no recibir\xE1n ning\xFAn comentario, el lector de pantalla ignorar\xE1 por completo el bot\xF3n al navegar por el formulario. Esto claramente puede ser muy confuso y frustrante.</p><p>En su lugar, sugiero que realice todas y cada una de las comprobaciones para asegurarse de que su formulario sea v\xE1lido antes de enviarlo en el m\xE9todo <code>sendForm</code> que creamos en <code>TasksForm</code>. Si todo sale bien, enviamos el formulario normalmente.</p><p>Si algo est\xE1 mal, establesca los errores necesarios en su formulario con las herramientas que acabamos de aprender para notificar al usuario que algo est\xE1 mal.</p><h2 id="terminando" tabindex="-1">Terminando <a class="header-anchor" href="#terminando" aria-hidden="true">#</a></h2><p>Como puede ver, con unas pocas l\xEDneas r\xE1pidas de <strong>HTML</strong> y algunos accesorios colocados estrat\xE9gicamente, logramos convertir nuestro componente <strong>AppInput</strong> en algo mucho m\xE1s accesible.</p><p>Sin embargo, quiero enfatizar que, en lo que respecta al tema de la accesibilidad, esto solo comienza a ara\xF1ar la superficie. \xA1Pero con estos pocos consejos, deber\xEDamos poder establecer el rumbo para una forma m\xE1s inclusiva y accesible para nuestros proyectos!</p>',46),c=[t];function D(i,F,d,y,u,m){return e(),a("div",null,c)}var C=s(r,[["render",D]]);export{A as __pageData,C as default};
